const model = 'qwen/qwen3.5-flash-02-23@reasoning_effort=none';

const promptSystem =
  'You are a test assistant for pharmacy classification pipeline. Return ONLY valid JSON.';

const promptUser = `
Smoke test for Polza.ai + Qwen via n8n.

Product: "Нурофен таблетки 200 мг, 10 шт"

Return JSON with keys:
- winner_source (llm | fallback_2b | none)
- category_id (number or null)
- confidence (0.0-1.0)
- explanation (1 sentence in Russian)
- needs_human_review (boolean)
`.trim();

return [{
  json: {
    model,
    prompt_system: promptSystem,
    prompt_user: promptUser,
    test_started_at: new Date().toISOString(),
  },
}];

function extractJsonString(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return JSON.stringify(value);
  let text = String(value).trim();
  const codeFenceMatch = text.match(/^```(?:json)?\s*\n?([\s\S]+?)\n?```\s*$/i);
  if (codeFenceMatch) text = codeFenceMatch[1].trim();
  return text;
}

return items.map((item, index) => {
  const j = item.json || {};
  const raw = j.output ?? j.text ?? j.response ?? j.content ?? null;
  const rawText = extractJsonString(raw);
  let parsed = null;
  let jsonOk = false;
  let jsonError = null;

  if (rawText) {
    try {
      parsed = JSON.parse(rawText);
      jsonOk = true;
    } catch (e) {
      jsonError = String(e);
    }
  }

  const required = ['winner_source', 'category_id', 'confidence', 'explanation', 'needs_human_review'];
  const missingKeys = jsonOk
    ? required.filter((k) => !(k in parsed))
    : required;

  return {
    json: {
      provider: 'polza.ai',
      model: j.model || 'qwen/qwen3.5-flash-02-23',
      test_started_at: j.test_started_at || null,
      test_finished_at: new Date().toISOString(),
      raw_output: rawText,
      parsed_json: parsed,
      json_ok: jsonOk,
      json_error: jsonError,
      judge_schema_ok: jsonOk && missingKeys.length === 0,
      missing_keys: missingKeys,
      status: jsonOk && missingKeys.length === 0 ? 'ok' : 'failed',
    },
    pairedItem: index,
  };
});
